js.home:
const cate=env.get('category')||'vodtype/115/';
const page=Number(env.get('page')||1);
const BASE=env.baseUrl.replace(/\/+$/, '');

if(cate==='ddd/'){
  const url=`${BASE}/ddd/`;
  const resp=await req(url,{timeout:30000});
  const html=resp.content||resp;
  if(!html) return [];
  const $=kitty.load(html);
  const modules=[];
  const allItems=[];

  // 统一解析函数
  function parseItem(el){
    const a=$(el).find('a.group-item');
    const id=new URL(a.attr('href')||'#',BASE).href;
    const title=a.find('p').text().trim();
    let cover=a.find('img').attr('data-src')||a.find('img').attr('src')||'';
    if(cover.startsWith('//')) cover='https:'+cover;
    if(cover.startsWith('/')) cover=BASE+cover;
    const remark=$(el).find('span.layui-badge.score').text().trim()||'HD';
    if(id&&title){ return {id,title,cover,remark}; }
    return null;
  }

  $('div.layui-col-md3.m-md6').each((i,el)=>{
    const item=parseItem(el);
    if(item) allItems.push(item);
  });

  // Banner: 前16个视频
  const bannerItems=allItems.slice(0,16).map(v=>({...v,remark:'精选'}));
  if(bannerItems.length){ modules.push({type:'banner',title:'首页推荐',videos:bannerItems}); }

  // List 模块: 后面每4个视频一组
  const listTitles=['大奶系列','网曝门事件','国产精品','步兵无码','起点传媒','乐播传媒'];
  for(let i=0;i<listTitles.length;i++){
    const groupItems=allItems.slice(16+i*4,16+(i+1)*4);
    if(groupItems.length){ modules.push({type:'list',title:listTitles[i],videos:groupItems}); }
  }

  return {type:'complex',data:modules};
} else {
  const url=`${BASE}/${cate.replace(/\/$/,'')}-${page}/`;
  const resp=await req(url,{timeout:30000});
  const html=resp.content||resp;
  if(!html) return [];
  const $=kitty.load(html);
  let items=[];
  $('.layui-col-md3').each((i,el)=>{
    const link=$(el).find('a.group-item').attr('href');
    const title=$(el).find('p').text().trim();
    let cover=$(el).find('img').attr('data-src')||$(el).find('img').attr('src')||'';
    if(cover){
      if(cover.startsWith('//')) cover='https:'+cover;
      if(cover.startsWith('/')) cover=BASE+cover;
    }
    const remark=$(el).find('span.layui-badge.score').text().trim();
    if(link&&title){
      let id=new URL(link,BASE).href;
      items.push({id,title,cover,remark});
    }
  });
  return items;
}

