const id=env.get('movieId')||'';
const url=new URL(id,env.baseUrl).href;
const resp=await req(url,{timeout:30000});
const html=resp.content||resp;
if(!html) return {};
const $=kitty.load(html);

let title=$('title').text().trim()||$('.vod-txt a').text().trim();
let cover=$('.vod-img img').attr('data-original')||$('.vod-img img').attr('src')||'';
if(cover){
  if(cover.startsWith('//')) cover='https:'+cover;
  if(cover.startsWith('/')) cover=env.baseUrl+cover;
}
let desc=$('.txt').text().trim();

let playlist=[];
let videos=[];

// 找到播放页链接
let playLink=$('a.play').attr('href');
if(playLink){
  let playUrl=new URL(playLink,env.baseUrl).href;
  const playResp=await req(playUrl,{timeout:30000});
  const playHtml=playResp.content||playResp;
  const $$=kitty.load(playHtml);
  const script=$$('script').filter((i,el)=>$$(el).html().includes('player_data')).html();
  if(script){
    try{
      const m=script.match(/player_data\s*=\s*(\{.*?\})/);
      if(m){
        const data=JSON.parse(m[1].replace(/\\\//g,'/'));
        if(data.url){
          videos.push({text:'播放',id:data.url,type:'direct'});
        }
      }
    }catch(e){}
  }
}

if(videos.length) playlist.push({title:'播放列表',videos});

return {id:url,title,cover,desc,playlist};

