js.detail:
const id = env.get('movieId') || '';
const url = new URL(id, env.baseUrl).href;
const resp = await req(url, { timeout: 30000, headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0 Safari/537.36', 'Referer': env.baseUrl, 'Accept-Language': 'en-US,en;q=0.9' } });
const html = resp.content || resp;
if (!html) return {};
let playlist = [];
let videos = [];

// 简介（正则作为字符串）
let desc = '';
const introRegexStr = "<div class=\\\"prose[\\s\\S]*?<p[^>]*>([\\s\\S]*?)<\\/p>";
const introRegex = new RegExp(introRegexStr, 'i');
const introMatch = html.match(introRegex);
if (introMatch) desc = introMatch[1].replace(/<[^>]+>/g, '').trim();

// 播放列表：正则作为字符串并用 new RegExp
const playRegexStr = "<a\\s+href=\\\"(https?:\\/\\/[^\\\"]+)\\\"[^>]*>\\s*<span[^>]*>\\s*(STREAMTAPE|MIXDROP|DOODSTREAM|BIGWARP)\\s*<br\\s*\\/?>(?:\\s*<\\/span>)?\\s*<\\/a>";
const playRegex = new RegExp(playRegexStr, 'gi');
let m;
while ((m = playRegex.exec(html)) !== null) {
 const playUrl = m[1].trim();
 const text = m[2].trim();
 // 嗅探分组（保留现有播放方式）
 videos.push({ text, id: playUrl, type: 'direct' });
}
if (videos.length > 0) playlist.push({ title: '播放列表(嗅探)', videos });

// 新增 iframe 播放分组
let iframeVideos = [];
playRegex.lastIndex = 0;
while ((m = playRegex.exec(html)) !== null) {
 const playUrl = m[1].trim();
 const text = m[2].trim();
 iframeVideos.push({ text, url: playUrl, type: 'iframe' });
}
if (iframeVideos.length > 0) playlist.push({ title: '播放列表(Iframe)', videos: iframeVideos });

// 封面和标题直接沿用 home 页抓到的
return { id: url, title: env.get('title') || '', cover: env.get('cover') || '', desc, playlist };

