js.home:
const cate = env.get('category') || 'comics?ordering=-datetime_updated';
const page = Number(env.get('page') || 1);
const offset = (page - 1) * 50;
const url = `${env.baseUrl}/${cate}&offset=${offset}&limit=50`;
const resp = await req(url, { timeout: 30000 });
const html = resp.content || resp;
if (!html) return [];

function decodeEntities(s) {
 return s.replace(/&#x27;/g, "'")
 .replace(/&quot;/g, '"')
 .replace(/&amp;/g, '&')
 .replace(/&lt;/g, '<')
 .replace(/&gt;/g, '>');
}

function parseListFromHtml(html) {
 const listAttrRegex = /list=(?:"([\s\S]*?)"|'([\s\S]*?)')/i;
 const listMatch = html.match(listAttrRegex);
 if (!listMatch) return [];
 let raw = listMatch[1] || listMatch[2] || '';
 if (!raw) return [];
 raw = decodeEntities(raw);

 // 尝试把单引号伪 JSON 转为合法 JSON 并解析
 let candidate = raw.replace(/\r?\n/g, ' ');
 candidate = candidate.replace(/\s*\,\s*\}/g, '}').replace(/\s*\,\s*\]/g, ']');
 // 将单引号替换为双引号（示例数据中安全），并对内嵌双引号做简单转义处理
 const doubleQuoted = candidate.replace(/'/g, '"');
 try {
 const arr = JSON.parse(doubleQuoted);
 if (Array.isArray(arr)) return arr;
 } catch (e) {
 // 解析失败则回退正则提取
 }

 // 回退：用正则在 raw 中逐条提取字段
 const out = [];
 const itemRegex = /'path_word'\s*:\s*'([^']+)'[\s\S]*?'name'\s*:\s*'([^']+)'[\s\S]*?'cover'\s*:\s*'([^']+)'[\s\S]*?'status'\s*:\s*(\d+)/g;
 let m;
 while ((m = itemRegex.exec(raw)) !== null) {
 out.push({ path_word: m[1], name: m[2], cover: m[3], status: Number(m[4]) });
 }
 return out;
}

const parsed = parseListFromHtml(html);
const items = [];
for (const it of parsed) {
 const path_word = it.path_word || it.pathWord || '';
 const title = it.name || it.title || '';
 const cover = it.cover || '';
 const status = (typeof it.status !== 'undefined') ? String(it.status) : '';
 const id = `${env.baseUrl}/comic/${path_word}`;
 let remark = '';
 if (status === '0') remark = '连载';
 else if (status === '1') remark = '完结';
 else if (status === '2') remark = '短篇';
 items.push({ id, title, cover, remark, desc: title });
}
return items;

