try { json = JSON.parse(data); } catch (e) { return []; }
const items = [];
if (json.results && json.results.list && Array.isArray(json.results.list)) {
 for (const it of json.results.list) {
 const path_word = it.path_word || '';
 const title = it.name || '';
 const cover = it.cover || '';
 const id = `${env.baseUrl}/comic/${path_word}`;
 let authors = '';
 if (it.author && Array.isArray(it.author)) {
 authors = it.author.map(a => a.name).join(', ');
 }
 items.push({ id, title, cover, remark: it.popular ? `热度 ${it.popular}` : '', desc: authors ? `作者: ${authors}` : title });
 }
}
return items;

js.detail:
const id = env.get('movieId') || '';
const url = new URL(id, env.baseUrl).href;
const resp = await req(url, { timeout: 30000 });
const html = resp.content || resp;
if (!html) return {};
let title = '';
let cover = '';
let desc = '';
let playlist = [];
let videos = [];

// 提取简介
const introRegex = /<p\s+class=["']intro["'][^>]*>([\s\S]*?)<\/p>/i;
const introMatch = html.match(introRegex);
if (introMatch) desc = introMatch[1].trim();

// 精确提取第一个章节链接
const chapterRegex = /<a[^>]*href=["']([^"']*\/comic\/[^"']*\/chapter\/[^"']*)["'][^>]*class=["'][^"']*comicParticulars-botton[^"']*["'][^>]*>[\s\S]*?開始閱讀[\s\S]*?<\/a>/i;
let chapterMatch = html.match(chapterRegex);

// 回退：匹配任意含 /chapter/ 的 a 标签
if (!chapterMatch) {
 const looseRegex = /<a[^>]*href=["']([^"']*\/chapter\/[^"']*)["'][^>]*>[\s\S]*?開始閱讀[\s\S]*?<\/a>/i;
 chapterMatch = html.match(looseRegex);
}

if (chapterMatch) {
 const href = chapterMatch[1];
 const playUrl = new URL(href, env.baseUrl).href;
 videos.push({ text: '開始閱讀', url: playUrl, type: 'iframe' });
 playlist.push({ title: '播放列表', videos });
}

// 标题
const titleRegex = /<title>([\s\S]*?)<\/title>/i;
const titleMatch = html.match(titleRegex);
if (titleMatch) title = titleMatch[1].trim();

// 封面
const coverRegex = /<meta[^>]*property=["']og:image["'][^>]*content=["']([^"']+)["']/i;
const coverMatch = html.match(coverRegex);
if (coverMatch) cover = coverMatch[1];

return { id: url, title, cover, desc, playlist };
